import React, { useState } from "react";
import { login, register } from "../api/apiService";
import { useNavigate } from "react-router-dom";

function Auth() {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    username: "",
    email: "",
    password: ""
  });

  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);

  const submit = async () => {
    try {
      // 🔥 BASIC VALIDATION
      if (!form.username || !form.password) {
        alert("Username & Password required ❌");
        return;
      }

      if (!isLogin && !form.email) {
        alert("Email required ❌");
        return;
      }

      setLoading(true);

      let res;

      if (isLogin) {
        res = await login({
          username: form.username,
          password: form.password
        });

        console.log("LOGIN RESPONSE FULL:", JSON.stringify(res, null, 2));

        // 🔥 SAFE TOKEN SAVE
        const token = res?.access_token || res?.token;

        if (!token) {
          throw new Error("Token not received from server");
        }

        localStorage.setItem("token", token);

        alert("Login Successful ✅");

        // ✅ BETTER REDIRECT
        navigate("/");

      } else {
        await register(form);

        alert("Register Successful ✅, अब Login करो");

        // 🔥 AUTO SWITCH TO LOGIN
        setIsLogin(true);

        // optional: clear password
        setForm({
          username: form.username,
          email: "",
          password: ""
        });
      }

    } catch (err) {
      console.error("Auth Error:", err);

      alert(
        err?.response?.data?.detail ||
        err.message ||
        "Something went wrong ❌"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: "30px", maxWidth: "400px", margin: "auto" }}>
      <h2>{isLogin ? "🔐 Login" : "📝 Register"}</h2>

      {/* USERNAME */}
      <input
        placeholder="Username"
        value={form.username}
        onChange={(e) =>
          setForm({ ...form, username: e.target.value })
        }
        style={inputStyle}
      />

      {/* EMAIL (REGISTER ONLY) */}
      {!isLogin && (
        <input
          placeholder="Email"
          value={form.email}
          onChange={(e) =>
            setForm({ ...form, email: e.target.value })
          }
          style={inputStyle}
        />
      )}

      {/* PASSWORD */}
      <input
        placeholder="Password"
        type="password"
        value={form.password}
        onChange={(e) =>
          setForm({ ...form, password: e.target.value })
        }
        style={inputStyle}
      />

      <button onClick={submit} disabled={loading} style={btnStyle}>
        {loading ? "Please wait..." : "Submit"}
      </button>

      <p
        style={{ cursor: "pointer", color: "blue", marginTop: "10px" }}
        onClick={() => setIsLogin(!isLogin)}
      >
        Switch to {isLogin ? "Register" : "Login"}
      </p>
    </div>
  );
}

// ================== STYLES ==================
const inputStyle = {
  width: "100%",
  padding: "10px",
  marginTop: "10px"
};

const btnStyle = {
  marginTop: "15px",
  width: "100%",
  padding: "10px",
  background: "crimson",
  color: "white",
  border: "none",
  cursor: "pointer"
};

export default Auth;
